/**
 * DOM Validator
 * Validates DOM elements against rules and adds error classes
 */
export default class DOMValidator {
  /**
   * Default error class to add to invalid elements
   */
  static errorClass = 'FlagBugIO-error';
  
  /**
   * Observer for real-time validation
   */
  static observer = null;
  
  /**
   * Map to store validation rules for elements
   */
  static validationRules = new Map();

  /**
   * Initialize real-time validation
   * @param {Object} fieldsConfig - Configuration for fields to validate
   */
  static initRealTimeValidation(fieldsConfig) {
    // Store validation rules for each element
    for (const selector in fieldsConfig) {
      const config = fieldsConfig[selector];
      const element = document.querySelector(selector);
      
      if (element) {
        // Store the validation rules for this element
        this.validationRules.set(element, {
          rules: config.rules,
          valueType: config.valueType || 'value'
        });
        
        // Add input event listener for real-time validation
        element.addEventListener('input', () => {
          this.validateElement(element, config.rules, config.valueType || 'value');
        });
        
        // For contenteditable elements, also validate on blur
        if (element.hasAttribute('contenteditable')) {
          element.addEventListener('blur', () => {
            this.validateElement(element, config.rules, config.valueType || 'value');
          });
        }
      }
    }
    
    // Set up observer for dynamically added elements
    this.setupObserver();
  }
  
  /**
   * Set up MutationObserver to watch for dynamically added elements
   */
  static setupObserver() {
    // Only set up the observer once
    if (this.observer) return;
    
    this.observer = new MutationObserver(mutations => {
      mutations.forEach(mutation => {
        // Check for attribute changes that might affect validation
        if (mutation.type === 'attributes' && 
            (mutation.attributeName === 'value' || mutation.attributeName === 'data-value')) {
          const element = mutation.target;
          
          // If we have validation rules for this element, validate it
          if (this.validationRules.has(element)) {
            const config = this.validationRules.get(element);
            this.validateElement(element, config.rules, config.valueType);
          }
        }
        
        if (mutation.addedNodes.length) {
          mutation.addedNodes.forEach(node => {
            // Check if the node is an element
            if (node.nodeType === 1) {
              // Check if we have validation rules for this element
              if (this.validationRules.has(node)) {
                const config = this.validationRules.get(node);
                this.validateElement(node, config.rules, config.valueType);
                
                // Add input event listener for real-time validation
                node.addEventListener('input', () => {
                  this.validateElement(node, config.rules, config.valueType);
                });
                
                // For contenteditable elements, also validate on blur
                if (node.hasAttribute('contenteditable')) {
                  node.addEventListener('blur', () => {
                    this.validateElement(node, config.rules, config.valueType);
                  });
                }
              }
              
              // Check for elements within the added node that match our selectors
              this.validationRules.forEach((config, element) => {
                const matches = node.querySelectorAll(this.getSelectorForElement(element));
                matches.forEach(match => {
                  this.validateElement(match, config.rules, config.valueType);
                  
                  // Add input event listener for real-time validation
                  match.addEventListener('input', () => {
                    this.validateElement(match, config.rules, config.valueType);
                  });
                  
                  // For contenteditable elements, also validate on blur
                  if (match.hasAttribute('contenteditable')) {
                    match.addEventListener('blur', () => {
                      this.validateElement(match, config.rules, config.valueType);
                    });
                  }
                });
              });
              
              // Check for hidden inputs
              const hiddenInputs = node.querySelectorAll('input[type="hidden"]');
              hiddenInputs.forEach(hiddenInput => {
                if (this.validationRules.has(hiddenInput)) {
                  const config = this.validationRules.get(hiddenInput);
                  this.validateElement(hiddenInput, config.rules, config.valueType);
                }
              });
            }
          });
        }
      });
    });
    
    // Start observing the document body for DOM changes
    this.observer.observe(document.body, {
      childList: true,
      subtree: true,
      attributes: true,
      attributeFilter: ['value', 'data-value']
    });
  }
  
  /**
   * Get a CSS selector for an element
   * @param {HTMLElement} element - The element to get a selector for
   * @returns {string} - CSS selector
   */
  static getSelectorForElement(element) {
    if (element.id) {
      return `#${element.id}`;
    } else if (element.className) {
      return `.${element.className.split(' ').join('.')}`;
    } else {
      return element.tagName.toLowerCase();
    }
  }

  /**
   * Validate a single DOM element
   * @param {HTMLElement} element - The DOM element to validate
   * @param {Object} rules - Validation rules
   * @param {string} valueType - Type of value to check ('textContent', 'value', 'innerHTML')
   * @returns {boolean} - Whether validation passed
   */
  static validateElement(element, rules, valueType = 'value') {
    if (!element) {
      console.error('Element not found');
      return false;
    }

    // Get the element's value based on valueType
    let value = valueType === 'textContent' 
      ? element.textContent 
      : valueType === 'innerHTML' 
        ? element.innerHTML 
        : element.value;
    
    // Check if this is a contenteditable with placeholder and the value equals the placeholder
    if (valueType === 'textContent' && 
        element.hasAttribute('contenteditable') && 
        element.hasAttribute('data-placeholder') &&
        value === element.getAttribute('data-placeholder')) {
      value = ''; // Treat placeholder text as empty value
    }
    
    // For hidden fields, check if there's a data-value attribute
    if (element.type === 'hidden' && element.hasAttribute('data-value')) {
      value = element.getAttribute('data-value');
    }
    
    let isValid = true;
    const errors = [];

    // Required check
    if (rules.required && (!value || value.trim() === '')) {
      isValid = false;
      errors.push('This field is required');
    }

    // Min length check
    if (rules.minLength && value.length < rules.minLength) {
      isValid = false;
      errors.push(`Minimum length is ${rules.minLength} characters`);
    }

    // Max length check
    if (rules.maxLength && value.length > rules.maxLength) {
      isValid = false;
      errors.push(`Maximum length is ${rules.maxLength} characters`);
    }

    // Pattern check
    if (rules.pattern && !rules.pattern.test(value)) {
      isValid = false;
      errors.push('Invalid format');
    }

    // Enum check
    if (rules.enum && !rules.enum.includes(value)) {
      isValid = false;
      errors.push(`Value must be one of: ${rules.enum.join(', ')}`);
    }

    // Custom validator function
    if (rules.validator && typeof rules.validator === 'function') {
      const customResult = rules.validator(value);
      if (customResult !== true) {
        isValid = false;
        errors.push(customResult || 'Invalid value');
      }
    }

    // Determine the target element (either the element itself or its parent for hidden inputs)
    const targetElement = (element.type === 'hidden' && element.parentElement) 
      ? element.parentElement 
      : element;

    // Add or remove error class and message based on validation result
    if (!isValid) {
      // Add error class
      targetElement.classList.add(this.errorClass);
      
      // Add tooltip with error message if specified
      if (rules.showErrorMessage !== false) {
        targetElement.setAttribute('title', errors.join('. '));
        
        // Create or update error message div
        let errorDiv = targetElement.nextElementSibling;
        if (!errorDiv || !errorDiv.classList.contains('FlagBugIO-error-message')) {
          errorDiv = document.createElement('div');
          errorDiv.classList.add('FlagBugIO-error-message');
          targetElement.parentNode.insertBefore(errorDiv, targetElement.nextSibling);
        }
        
        errorDiv.textContent = errors.join('. ');
        errorDiv.style.display = 'block';
      }
    } else {
      // Remove error class
      targetElement.classList.remove(this.errorClass);
      targetElement.removeAttribute('title');
      
      // Remove error message div if it exists
      const errorDiv = targetElement.nextElementSibling;
      if (errorDiv && errorDiv.classList.contains('FlagBugIO-error-message')) {
        errorDiv.style.display = 'none';
      }
    }

    return isValid;
  }

  /**
   * Validate multiple form fields
   * @param {Object} fieldsConfig - Configuration for fields to validate
   * @param {boolean} realTime - Whether to enable real-time validation
   * @returns {boolean} - Whether all validations passed
   */
  static validateForm(fieldsConfig, realTime = false) {
    let isFormValid = true;

    // If real-time validation is requested, set it up
    if (realTime) {
      this.initRealTimeValidation(fieldsConfig);
    }

    for (const selector in fieldsConfig) {
      const config = fieldsConfig[selector];
      const element = document.querySelector(selector);
      
      if (!element) {
        console.error(`Element not found: ${selector}`);
        isFormValid = false;
        continue;
      }

      const isFieldValid = this.validateElement(
        element, 
        config.rules, 
        config.valueType || 'value'
      );

      if (!isFieldValid) {
        isFormValid = false;
      }
    }

    return isFormValid;
  }


  /**
   * Create and validate a form with default validation rules
   * @param {boolean} realTime - Whether to enable real-time validation
   * @returns {boolean} - Whether all validations passed
   */
  static createFormValidate(realTime = true) {
    const defaultFieldsConfig = {
      '.FlagBugIO-form-title': { rules: { required: true, minLength: 3, maxLength: 100 }, valueType: 'textContent' },
      '.FlagBugIO-form-description': { rules: { required: true, minLength: 10 }, valueType: 'textContent'},
      '.FlagBugIO-form-due-date-select input[type="hidden"]': { rules: { required: true } },
      '.FlagBugIO-form-assignee-select input[type="hidden"]': { rules: { required: true } },
      '.FlagBugIO-form-priority-select input[type="hidden"]': { rules: { required: true } },
      // '.FlagBugIO-form-status-select input[type="hidden"]': { rules: { required: true } },
    };
    
    

    return this.validateForm(defaultFieldsConfig, realTime);
  }

  /**
   * Clear all validation errors
   * @param {string} formSelector - Selector for the form or container
   */
  static clearErrors(formSelector) {
    const container = document.querySelector(formSelector);
    if (!container) return;

    const errorElements = container.querySelectorAll(`.${this.errorClass}`);
    errorElements.forEach(element => {
      element.classList.remove(this.errorClass);
      element.removeAttribute('title');
      // Remove error message divs
      const errorDiv = element.nextElementSibling;
      if (errorDiv && errorDiv.classList.contains('FlagBugIO-error-message')) {
        errorDiv.style.display = 'none';
      }
    });
  }
}
