export default class apiModel  {
    constructor(state) {
        this.state = state;
        //this.api_endpoint = "https://bugvault.2cube.studio/api/v1/";
        this.api_endpoint = "http://192.168.0.159:3030/api/v1/";

        this.slug = {
            ALL_BUGS: "tasks/?",
            GET_PROJECT_BY_DOMAIN: "project?domain=",
            ADD_BUG: "tasks/tasks-create",
            UPDATE_BUG: "tasks/edit",
            
        }


        

    }

    // pass slug and params
    endPoint( slug, params ) {
        if(!params){ return `${this.api_endpoint}${this.slug[slug]}`; }
        return `${this.api_endpoint}${this.slug[slug]}${params}`;
    }

    async getProject() {
        try {
            const endpoint = this.endPoint('GET_PROJECT_BY_DOMAIN',window.location.hostname);
            // const endpoint = this.endPoint('GET_PROJECT_BY_DOMAIN','1725.23');
            const response = await fetch(endpoint);
            if (!response.ok) {
                throw new Error('Network response was not ok');
            }
            const data = await response.json();
            if (data.properties.projects) {
                const projects = data.properties.projects;

                const user = {
                    user: projects.created_by,
                    role: projects.created_by_role,
                    project: projects.project_id
                }

                this.state.setState('user',user.user);
                this.state.setState('role',user.role);
                this.state.setState('project',user.project);
                
                const team = data.properties.member;
                const tempTeam = [];
                team.forEach(member => {
                    if( member.role_in_project === 'viewer' ){ return; }
                    tempTeam.push({
                        value: member.user_id,
                        label: member.user_name,
                        imageUrl: member.avatar || null
                    });
                });
                this.state.setState('teams',tempTeam);
            } else {
                console.log('No Project found');
                return null;
            }
        } catch (error) {
            console.error('Error:', error);
            throw error;
        }
    }

    async addBug(bug) {
        const endpoint = this.endPoint('ADD_BUG');
        const formdata = new FormData();
        formdata.append("payload",bug);

        const data = await fetch(endpoint,{
            method: 'POST',
            body: formdata
        });

        if(data.ok){
            const response = await data.json();
            this.state.storage.addNewBug(response);
            this.state.addBug(response);
            return true;
        }else{
            return false;
        }
        
    }

    async updateBug(bug) {
        console.log('updateBug in',bug)
        const endpoint = this.endPoint('UPDATE_BUG');
        const data = await fetch(endpoint,{
            method: 'PATCH',
            headers: { 'Content-Type': 'application/json'},
            body: JSON.stringify(bug)
        });

        if(data.ok){
            const response = await data.json();
            this.state.storage.updateBug(bug.id, response.properties);
            this.state.updateBug(bug.id, response.properties);
            return true;
        }else{
            return false;
        }
        
    }



    async getAllBugs() {
        const endpoint = this.endPoint('ALL_BUGS',`project_id=${this.state.project}`);
        const response = await fetch(endpoint);
        const data = await response.json();
        if(response.status === 401){
            return [];
        }else{
            this.state.storage.setItem('bugs', data.properties);
            return data.properties;
        }
    }
};
