import { AppController } from "./src/controller/AppController.js";
import ExplorerController from "./src/controller/ExplorerController.js";
import DatePicker from "./src/utils/date-picker.js";
import Dragable from "./src/utils/dragable.js";
import DropdownSelect from "./src/utils/dropdown.js";
import Tooltip from "./src/utils/tooltip.js";
import ContentEditable from "./src/utils/contenteditable.js";
import State from "./state.js";


class FlagBugApp{
    constructor() {
        this.state = new State();
        this.app = new AppController(this);
        this.app.init();

        new Dragable(document.getElementById('widgetOptionPicker'));

        // Initialize the Explorer Controller
        this.explorer = new ExplorerController(this);
        this.explorer.init();

        // Initialize all contenteditable elements
        ContentEditable.initAll();

        const datePicker = new DatePicker({
            element: document.querySelector('#tooltip'),
            format: 'D MMMM YYYY',
            selectedDate: '2025-04-11T14:15:27.103Z',
            quickDateOptions: [
                { label: "Today", date: new Date() },
                { label: "Tomorrow", date: new Date(new Date().getTime() + 24 * 60 * 60 * 1000) },
                { label: "Next 4 days", date: new Date(new Date().getTime() + 4 * 24 * 60 * 60 * 1000) },
            ]
        });

        const datePicker2 = new DatePicker({
            element: document.querySelector('#my-dropdown'),
            format: 'DD MMMM YYYY',
            selectedDate: '2025-04-11T14:15:27.103Z',
            quickDateOptions:false
        });
        
        // Listen for date change events
        datePicker.addEventListener('change', (event) => {
            console.log('Selected date:', event.data.iso);
        });
    }
}



document.addEventListener('DOMContentLoaded', () => {
    new FlagBugApp();
});
