import { InlineController } from './InlineController.js';
import { CaptureController } from './CaptureController.js';
import DropdownSelect from '../utils/dropdown.js';
import Tooltip from '../utils/tooltip.js';
import DOMValidator from '../utils/domValidator.js';
import DatePicker from '../utils/date-picker.js';

export class AppController {
  constructor(state) {
    // Get the state from the app
    this.state = state.state;
    this.role = this.state.role;
    this.permissions = this.state.permissions[this.role];
    this.currentOpenBugId = null; // Track currently open bug

    this.availableTypes = {
      inline: new InlineController(this),
      capture: new CaptureController(this)
    };
    
    // Listen for marker clicks
    if(this.permissions.read){
      document.addEventListener('markerClicked', (e) => {
        if(this.state.appStage !== 'init' && this.state.appStage !== 'VIEW_BUG') return;
        
        const clickedBugId = e.detail.id;
        console.log("Marker clicked event, current bug ID:", this.currentOpenBugId, "clicked bug ID:", clickedBugId);
        
        const previousBugId = this.currentOpenBugId;
        this.viewBug(clickedBugId, previousBugId);
        
        this.currentOpenBugId = clickedBugId;
        console.log("Setting current bug ID to:", this.currentOpenBugId);
        
        
      });
    }
  }

  init() {
    // Use the EnabledTypes directly from state
    this.state.EnabledTypes.forEach(type => {
      if (this.availableTypes[type]) {
        console.log(`Initializing ${type} controller`);
        this.availableTypes[type].init();
      }
    });
  }
  
  viewBug(bugId, previousBugId) {

    document.getElementById(`FlagBugMarker-${bugId}`).classList.add('FlagBugMarker-active');
    const explorerItem = document.querySelector(`.FlagBugMarker-explorer-item[data-bug-id="${bugId}"]`);
        if (explorerItem) {
          explorerItem.classList.add('FlagBugMarker--item-active');
        }

    
    const existingForms = document.querySelectorAll('.FlagBugIO-form-wrapper');
    
    if (bugId === previousBugId && existingForms.length > 0) {
      console.log("Same bug clicked again and form exists, closing form");
      existingForms.forEach(form => this.removeForm(form,previousBugId));
      this.state.setState('appStage', 'init');
      return;
    }
    
    if (existingForms.length > 0) {
      console.log("Closing existing forms before opening new bug");
      existingForms.forEach(form => this.removeForm(form,previousBugId));
    }
    
    this.state.setState('appStage', 'VIEW_BUG');
    console.log("Setting app stage to VIEW_BUG");
    
    
    
    let TYPE = '';

    // ROLE is Blank
    if(!this.role){
      console.log("No role defined, returning");
      return;
    }
    
    if(!this.permissions.read){
      console.log("No read permissions, returning");
      return;
    }

    if(!this.permissions.write){
      TYPE = 'view';
    }else if(this.permissions.write){
      TYPE = 'edit';
    }
    console.log("Form type:", TYPE);
    
    const bug = this.state.getBugById(bugId);
    if (!bug){
      console.error(`Bug with ID ${bugId} not found`);
      return;
    }
    
    const form = this.availableTypes['inline'].view.viewBug(bug,TYPE);
    this.bugInfoTooltip(bug);
    this.bugDropdown(form,bug,TYPE);
    
    

    // Ensure the form is visible
    setTimeout(() => {
      console.log("Form in DOM:", document.body.contains(form));
      console.log("Form display style:", window.getComputedStyle(form).display);
    }, 100);
    
    form.querySelector('#cancel-btn').addEventListener('click', () => {
      this.removeForm(form,bugId);
      this.state.setState('appStage', 'init');
    });
        
    if(!this.permissions.write){
      return;
    }

    const isValid = DOMValidator.createFormValidate(true);
    if (!isValid) {
      console.error('Form validation failed');
      return;
    }

    form.querySelector('#submit-btn').addEventListener('click', () => {
      const title = form.querySelector('.FlagBugIO-form-title').textContent;
      const description = form.querySelector('.FlagBugIO-form-description').textContent;
      const assigneeValue = form.querySelector('.FlagBugIO-form-assignee-select input[type="hidden"]').value;

      const priority = form.querySelector('.FlagBugIO-form-priority-select input[type="hidden"]').value;
      const status = form.querySelector('.FlagBugIO-form-status-select input[type="hidden"]').value;
      const dueDate = form.querySelector('.FlagBugIO-form-due-date-select input[type="hidden"]').value;


      const assignee = assigneeValue  ? assigneeValue.split(',').map(id => parseInt(id.trim(), 10)) : [];
      
      const apiJson = {
        "id": bugId,
        "assigned_to": assignee,
        "title": title,
        "description": description,
        "status": status,
        "priority": priority,
        "due_date": dueDate,    
      }




      const isValid = DOMValidator.createFormValidate(false);
      if (!isValid) {
        console.error('Form validation failed');
        return;
      }
      
      this.state.api.updateBug(apiJson).then(data => {
        if(data){
          this.removeForm(form,bugId);
          this.state.setState('appStage', 'init');
        }else{
          console.error('Error saving bug');
          this.state.setState('appStage', 'SAVE_BUG_ERROR');
        }
      });
    });
  }

  bugDropdown(form,bug,TYPE) {
      console.log("Bug Assignee:",this.state.teams, bug.assigned_to);
      new DropdownSelect({
        element: form.querySelector('.FlagBugIO-form-assignee-select'),
        data: this.state.teams,
        type: "multi",
        styleType: "avatar",
        placeholder: "Select a team or member",
        permissions: TYPE,
        preselected: [bug.assigned_to || '' ]
    });

    // status dropdown
    new DropdownSelect({
      element: form.querySelector('.FlagBugIO-form-status-select'),
      data: this.state.status,
      type: "single",
      styleType: "avatar",
      placeholder: "Please select a status",
      permissions: TYPE,
      preselected: [bug.status || '' ],
      searchable: false
    });

    // priority dropdown
    new DropdownSelect({
      element: form.querySelector('.FlagBugIO-form-priority-select'),
      data: this.state.priority,
      type: "single",
      styleType: "avatar",
      placeholder: "Please select a priority",
      permissions: TYPE,
      preselected: [bug.priority || '' ],
      searchable: false,
      className: "DropdownSelect--auto DropdownSelect--avatar--small"
    });

    new DatePicker({
      element: form.querySelector('.FlagBugIO-form-due-date-select'),
      format: 'DD MMMM YYYY',
      selectedDate: bug.due_date || null,
      permissions: TYPE
    });
  }

  bugInfoTooltip(bug) {
    const screeninfo = bug.screeninfo;
    const tooltip_html = `
        <div class="bug-info">
            <div class="bug-info-line">
                <div class="bug-info-label">Browser</div>
                <div class="bug-info-value">${screeninfo.browserInfo.name}</div>
            </div>
            <div class="bug-info-line">
                <div class="bug-info-label">Os</div>
                <div class="bug-info-value">${screeninfo.os.name}</div>
            </div>
        
            <div class="bug-info-line">
                <div class="bug-info-label">Device</div>
                <div class="bug-info-value">${screeninfo.os.type}</div>
            </div>
        
            <div class="bug-info-line">
                <div class="bug-info-label">Resolution</div>
                <div class="bug-info-value">${screeninfo.document.width}x${screeninfo.document.height}</div>
            </div>
        </div>
    `;
    new Tooltip({
      selector: '.FlagBugIO-bug-info',
      dataAttributes: true,
      trigger: 'hover',
      interactive: true,
      content: tooltip_html,
      html: true,
      offset: 10
    });

  }

  removeForm(form,formId = null) {

    if (form) {
      form.classList.remove('fade-in');
      if (formId) {
        document.getElementById(`FlagBugMarker-${formId}`).classList.remove('FlagBugMarker-active');  
        // FlagBugMarker-explorer-item class with data-bug-id
        const explorerItem = document.querySelector(`.FlagBugMarker-explorer-item[data-bug-id="${formId}"]`);
        if (explorerItem) {
          explorerItem.classList.remove('FlagBugMarker--item-active');
        }
      }
      setTimeout(() => {
        form.remove();  
      }, 300);
      
      this.currentOpenBugId = null;
      
    }
  }
}
