import Storage from "./src/utils/storage.js";
import Marker from "./src/utils/marker.js";
import apiModel from "./src/model/apiModel.js";


export default class State {
    constructor() {
        this.devMode = false;
        this.storage = new Storage();
        this.marker = new Marker(this);


        this.user = null;
        this.role = 'admin';
        this.project = null;

        this.api = new apiModel(this);

        this.permissions = {
            "viewer":{ "read": true, "write": false, "delete": false },
            "collaborator":{ "read": true, "write": true, "delete": true },
            "admin":{ "read": true, "write": true, "delete": true }
        };

        this.teams = [
            {
                "label": "Developers",
                "value": "devloper",
                "children": [
                    { "value": "1", "label": "Pratik", "imageUrl": "https://i.pravatar.cc/30?img=1" },
                    { "value": "2", "label": "Vikram", "imageUrl": "https://i.pravatar.cc/30?img=2" }
                ]
            },
            {
                "label": "Sales",
                "value": "sales",
                "children": [
                    { "value": "3", "label": "kamlesh", "imageUrl": "https://i.pravatar.cc/30?img=3" },
                    { "value": "4", "label": "Isha", "imageUrl": "https://i.pravatar.cc/30?img=36" },
                    { "value": "5", "label": "Nilesh", "imageUrl": "https://i.pravatar.cc/30?img=5" }
                ]
            }
        ];

        this.teams1 = [
            { "value": "1", "label": "Pratik", "imageUrl": "https://i.pravatar.cc/30?img=1" },
            { "value": "2", "label": "Vikram", "imageUrl": "https://i.pravatar.cc/30?img=2" },
            { "value": "3", "label": "kamlesh", "imageUrl": "https://i.pravatar.cc/30?img=3" },
            { "value": "4", "label": "Isha", "imageUrl": "https://i.pravatar.cc/30?img=36" },
            { "value": "5", "label": "Nilesh", "imageUrl": "https://i.pravatar.cc/30?img=5" }
        ];

        this.status = [
            { "label": "Open", "value": "open" },
            { "label": "In Progress", "value": "progress" },
            { "label": "Completed", "value": "completed"},
            { "label": "Resolved", "value": "resolved"},
            { "label": "Archived", "value": "archived"}
        ];

        this.priority = [
            { "label": "Low", "value": "low", "imageUrl": "https://placehold.co/30x30/3f51b6/3f51b6" },
            { "label": "Medium", "value": "medium", "imageUrl": "https://placehold.co/30x30/fec901/fec901" },
            { "label": "High", "value": "high", "imageUrl": "https://placehold.co/30x30/ff5723/ff5723" }
        ];


        this.explorer = true;

        this.EnabledTypes = ['inline'];
        this.bug = null;
        this.bugType = 'inline'; // inline , capture
        this.appStage = 'init';
        this.bugs = this.storage.getBugs() || [];
        this.overlay = { x: 0, y: 0, width: 0, height: 0, scrollX: 0, scrollY: 0, vh: 0, vw: 0 }
        
        
        this.getProject().then(() => {
            this.loadBugs();
        });
    }

    getState(option) {
        return this[option];
    }

    setState(option, value) {
        if (this.hasOwnProperty(option)) {
            this[option] = value;
            console.log(`State updated: ${option} = ${value}`);
        } else {
            console.warn(`Cannot set undefined property: ${option}`);
        }
    }

    

    // addBug
    addBug(bug) {
        this.bugs.push(bug);
        this.storage.setItem('bugs', this.bugs);
    }

    // update bug
    updateBug(id, data) {
        const bug = this.bugs.find(bug => bug.id === id);
        if (bug) {
            Object.assign(bug, data);
            this.storage.setItem('bugs', this.bugs);
        }
    }

    // get user from API
    async getProject() {
        if(this.devMode){ return; }

        await this.api.getProject().then(data => {
            if(!data){
                return false;
            }else{
                this.user = data.user;
                this.role = data.role;
                this.project = data.project;
                return true;
            }
        }).catch(error => {
            console.error('Error fetching user:', error);
            return false;
        });
    }


    // Load bugs from storage and create markers
    async loadBugs() {
        if(this.devMode){
            this.bugs = this.storage.getBugs() || [];
            this.marker.loadMarker(this.bugs);
            return;
        }

        await this.api.getAllBugs().then(data => {
            this.bugs = data || [];
            this.marker.loadMarker(this.bugs);
            return data;
        });
        
        
    }

    // Get all bugs
    getBugs() {
        return this.bugs;
    }

    // Get a specific bug by ID
    getBugById(id) {
        return this.bugs.find(bug => bug.id === id);
    }


    
}

