import { InlineModel } from "../model/InlineModel.js";
import DropdownSelect from "../utils/dropdown.js";
import Overlay from "../utils/overlay.js";
import { InlineView } from "../view/InlineView.js";
import DOMValidator from "../utils/domValidator.js";
import DatePicker from "../utils/date-picker.js";

export class InlineController {
  constructor(state) {
    this.state = state.state;

    this.view = new InlineView();
    this.model = new InlineModel(this.state);

    this.overlay = new Overlay();
    this.marker = this.state.marker;

  }

  init() {
    this.view.renderButton();
    this.view.bindClick(() => {
      if(this.state.appStage === 'init'){
        this.state.setState('bugType', 'inline');
        this.state.setState('appStage', 'inline');
        this.overlay.show();

        this.overlay.overlay.addEventListener('click', (e) => {
          const viewportInfo = this.overlay.getInfo(e);
          this.state.setState('overlay', viewportInfo);
          this.state.setState('appStage', 'OVERLAY_CLICKED');
          this.overlay.hide();
          const form = this.view.renderForm(viewportInfo,'inline');
          
          console.log('form created',form);
          new DropdownSelect({
            element: form.querySelector('.FlagBugIO-form-assignee-select'),
            data: this.state.teams,
            type: "single",
            styleType: "avatar",
            placeholder: "Select a team or member",
            preselected: [this.state.user]
          });

          new DropdownSelect({
            element: form.querySelector('.FlagBugIO-form-priority-select'),
            data: this.state.priority,
            type: "single",
            styleType: "avatar",
            placeholder: "Select a team or member",
            // preselected: ['low']
          });

          new DatePicker({
            element: form.querySelector('.FlagBugIO-form-due-date-select'),
            format: 'DD MMMM YYYY'  // Will display as "11 April 2025" without leading 
          });
          
          this.saveBug(form,viewportInfo);
          form.querySelector('#cancel-btn').addEventListener('click', () => {
            this.removeForm(form);
            this.state.setState('appStage', 'init');
          });
        });
      }
    });
  }



  saveBug(form,viewportInfo){
    form.querySelector('#submit-btn').addEventListener('click', async () => {
      const isValid = DOMValidator.createFormValidate();

      if (!isValid) {
        console.error('Form validation failed');
        return;
      }
      
      const title = form.querySelector('.FlagBugIO-form-title').textContent;
      const description = form.querySelector('.FlagBugIO-form-description').textContent;
      const assigneeValue = form.querySelector('.FlagBugIO-form-assignee-select input[type="hidden"]').value;
      const priority = form.querySelector('.FlagBugIO-form-priority-select input[type="hidden"]').value;

      
      const assignee = assigneeValue  ? assigneeValue.split(',').map(id => parseInt(id.trim(), 10)) : [];

      

      const apiJson = {
        "project_id": this.state.project,
        "assigned_to": assignee,
        "title": title,
        "mode": "comment",
        "href": window.location.href,
        "description": description,
        "status": "open",
        "priority": priority || 'low',
        "due_date": "2025-04-05",    
        "screeninfo": {
            "pixelRatio": window.devicePixelRatio,
            "userAgent": navigator.userAgent,
            "os": {
                "name": navigator.platform,
                "version": navigator.appVersion,
                "type": navigator.platform
            },
            "browserInfo": {
                "name": navigator.appName,
                "version": navigator.appVersion,
                "engine": navigator.product
            },
            "document": this.state.overlay
        }
      }
      
      await this.state.api.addBug(JSON.stringify(apiJson)).then(data => {
        if(data){
          this.marker.addMarker(data.id,this.state.overlay,this.state.storage.getBugCount());
          this.state.setState('appStage', 'SAVE_BUG_SUCCESS');
        }else{
          console.error('Error saving bug');
          this.state.setState('appStage', 'SAVE_BUG_ERROR');
        }
      });

      this.removeForm(form);
      
      
      
      
    });
  }


  removeForm(form) {
    if (form) {
      form.remove();
    }
  }

  


}
