export default class ContentEditable {
    constructor(element) {
        this.element = element;
        this.placeholder = element.getAttribute('data-placeholder');
        this.init();
    }

    init() {
        this.element.addEventListener('focus', this.handleFocus.bind(this));
        this.element.addEventListener('blur', this.handleBlur.bind(this));
        this.element.addEventListener('input', this.handleInput.bind(this));
        
        // Initialize placeholder state
        this.updatePlaceholder();
    }
    
    handleFocus() {
        if (this.element.textContent === this.placeholder) {
            this.element.textContent = '';
            this.element.classList.remove('placeholder');
        }
    }
    
    handleBlur() {
        this.updatePlaceholder();
    }
    
    handleInput() {
        if (this.element.textContent === this.placeholder) {
            this.element.classList.add('placeholder');
        } else {
            this.element.classList.remove('placeholder');
        }
    }
    
    updatePlaceholder() {
        if (this.element.textContent.trim() === '' && this.placeholder) {
            this.element.textContent = this.placeholder;
            this.element.classList.add('placeholder');
        }
    }
    
    // Static method to initialize all contenteditable elements with placeholders
    static initAll() {
        const elements = document.querySelectorAll('[contenteditable][data-placeholder]');
        const instances = Array.from(elements).map(element => new ContentEditable(element));
        
        // Set up MutationObserver to watch for new contenteditable elements
        ContentEditable.setupObserver();
        
        return instances;
    }
    
    // Set up MutationObserver to watch for dynamically added elements
    static setupObserver() {
        // Only set up the observer once
        if (ContentEditable.observer) return;
        
        ContentEditable.observer = new MutationObserver(mutations => {
            mutations.forEach(mutation => {
                if (mutation.addedNodes.length) {
                    mutation.addedNodes.forEach(node => {
                        // Check if the node is an element
                        if (node.nodeType === 1) {
                            // Check if the node itself is a contenteditable with placeholder
                            if (node.hasAttribute('contenteditable') && node.hasAttribute('data-placeholder')) {
                                new ContentEditable(node);
                            }
                            
                            // Check for contenteditable elements within the added node
                            const editables = node.querySelectorAll('[contenteditable][data-placeholder]');
                            if (editables.length) {
                                editables.forEach(el => new ContentEditable(el));
                            }
                        }
                    });
                }
            });
        });
        
        // Start observing the document body for DOM changes
        ContentEditable.observer.observe(document.body, {
            childList: true,
            subtree: true
        });
    }
    
    // Get the actual content (excluding placeholder)
    getValue() {
        return this.element.textContent === this.placeholder ? '' : this.element.textContent;
    }
    
    // Set content
    setValue(value) {
        this.element.textContent = value;
        this.updatePlaceholder();
    }
}
