export default class DatePicker {
    constructor({ 
        element, 
        selectedDate = null, 
        minDate = null, 
        maxDate = null, 
        format = "yyyy-MM-dd",
        showAdjacentMonthDays = true,
        quickDateOptions = null
    }) {
        this.element = element;
        this.selectedDate = selectedDate ? new Date(selectedDate) : null;
        this.minDate = minDate ? new Date(minDate) : null;
        this.maxDate = maxDate ? new Date(maxDate) : null;
        this.format = format;
        this.showAdjacentMonthDays = showAdjacentMonthDays;
        this.currentMonth = this.selectedDate ? new Date(this.selectedDate) : new Date();
        this.isOpen = false;
        this.eventListeners = {};
        
        // Set default quick date options if none provided
        const today = new Date();
        if(quickDateOptions){
            this.quickDateOptions = quickDateOptions || [
                { label: "Today", date: new Date() },
                { label: "Tomorrow", date: new Date(today.getTime() + 24 * 60 * 60 * 1000) },
                { label: "In 4 days", date: new Date(today.getTime() + 4 * 24 * 60 * 60 * 1000) }
            ];
        }
        
        this.prefix = "FlagBugIO--";
        this.staticClass = {
            container: `${this.prefix}datepicker-container`,
            input: `${this.prefix}datepicker-input`,
            calendar: `${this.prefix}datepicker-calendar`,
            header: `${this.prefix}datepicker-header`,
            days: `${this.prefix}datepicker-days`,
            day: `${this.prefix}datepicker-day`
        };
        
        // First render the elements
        this.render();
        // Then set up event listeners
        this.setupEventListeners();
    }
    
    render() {
        this.element.classList.add(this.staticClass.container);
        
        // Create hidden input field for ISO date value
        this.hiddenField = document.createElement("input");
        this.hiddenField.type = "hidden";
        this.hiddenField.className = `${this.prefix}datepicker-hidden`;
        
        // Add a name attribute to make it work with forms
        this.hiddenField.name = `datepicker-${Date.now()}`;
        
        // Set initial value if a date is selected
        if (this.selectedDate) {
            this.hiddenField.value = this.selectedDate.toISOString();
        }
        
        this.element.appendChild(this.hiddenField);
        
        // Create input field
        this.inputField = document.createElement("input");
        this.inputField.type = "text";
        this.inputField.className = this.staticClass.input;
        this.inputField.classList.add("FlagBugIO--control");
        this.inputField.readOnly = true;
        this.inputField.placeholder = "Select date";
        
        if (this.selectedDate) {
            this.inputField.value = this.formatDate(this.selectedDate);
        }
        
        this.element.appendChild(this.inputField);
    }
    
    setupEventListeners() {
        this.inputField.addEventListener("click", () => this.toggleCalendar());
        
        // Handle click outside
        document.addEventListener("click", (e) => {
            if (this.isOpen && !this.element.contains(e.target)) {
                this.closeCalendar();
            }
        });
    }
    
    toggleCalendar() {
        if (this.isOpen) {
            this.closeCalendar();
        } else {
            this.openCalendar();
        }
    }
    
    openCalendar() {
        if (this.calendar) {
            this.calendar.remove();
        }
        
        this.createCalendar();
        this.isOpen = true;
        
        setTimeout(() => {
            if (this.calendar) {
                this.calendar.classList.add("fade-in");
            }
        }, 50);
    }
    
    closeCalendar() {
        if (this.calendar) {
            this.calendar.classList.remove("fade-in");
            setTimeout(() => {
                if (this.calendar) {
                    this.calendar.remove();
                    this.calendar = null;
                }
            }, 250);
        }
        this.isOpen = false;
    }
    
    createCalendar() {
        this.calendar = document.createElement("div");
        this.calendar.className = `${this.staticClass.calendar} fade-in-el`;
        
        // Create quick date picker section
        if(this.quickDateOptions){
            const quickDatePicker = document.createElement("div");
            quickDatePicker.className = `${this.prefix}quick-date-picker`;
            
            // Create divs for each quick date option
            this.quickDateOptions.forEach(option => {
                const quickDateBtn = document.createElement("div");
                quickDateBtn.className = `${this.prefix}quick-date-btn`;
                quickDateBtn.textContent = option.label;
                
                // Check if this option is selectable
                if (this.isDateSelectable(option.date)) {
                    quickDateBtn.addEventListener("click", () => {
                        this.selectDate(option.date);
                    });
                } else {
                    quickDateBtn.classList.add("disabled");
                }
                
                quickDatePicker.appendChild(quickDateBtn);
            });
            
            // Add quick date picker to calendar
            this.calendar.appendChild(quickDatePicker);
        }
        
        // Create header with month/year and navigation
        const header = document.createElement("div");
        header.className = this.staticClass.header;
        
        const prevBtn = document.createElement("div");
        prevBtn.innerHTML = "&#10094;";
        prevBtn.className = "prev-month";
        prevBtn.addEventListener("click", (e) => {
            e.stopPropagation();
            this.prevMonth();
        });
        
        const nextBtn = document.createElement("div");
        nextBtn.innerHTML = "&#10095;";
        nextBtn.className = "next-month";
        nextBtn.addEventListener("click", (e) => {
            e.stopPropagation();
            this.nextMonth();
        });
        
        const monthYearText = document.createElement("span");
        monthYearText.textContent = this.formatMonthYear(this.currentMonth);
        
        header.appendChild(prevBtn);
        header.appendChild(monthYearText);
        header.appendChild(nextBtn);
        
        this.calendar.appendChild(header);
        
        // Create weekday headers
        const weekdays = ["Su", "Mo", "Tu", "We", "Th", "Fr", "Sa"];
        const daysContainer = document.createElement("div");
        daysContainer.className = this.staticClass.days;
        
        weekdays.forEach(day => {
            const dayEl = document.createElement("div");
            dayEl.className = "weekday";
            dayEl.textContent = day;
            daysContainer.appendChild(dayEl);
        });
        
        // Create calendar days
        this.renderCalendarDays(daysContainer);
        
        this.calendar.appendChild(daysContainer);
        this.element.appendChild(this.calendar);
    }
    
    renderCalendarDays(container) {
        const year = this.currentMonth.getFullYear();
        const month = this.currentMonth.getMonth();
        
        const firstDay = new Date(year, month, 1);
        const lastDay = new Date(year, month + 1, 0);
        
        const firstDayOfWeek = firstDay.getDay();
        const daysInMonth = lastDay.getDate();
        
        // Previous month days
        if (firstDayOfWeek > 0) {
            const prevMonth = new Date(year, month, 0);
            const prevMonthDays = prevMonth.getDate();
            
            for (let i = 0; i < firstDayOfWeek; i++) {
                const dayEl = document.createElement("div");
                dayEl.className = `${this.staticClass.day} inactive disabled`;
                
                if (this.showAdjacentMonthDays) {
                    const day = prevMonthDays - firstDayOfWeek + i + 1;
                    dayEl.textContent = day;
                    
                    // Create date for previous month day
                    const prevMonthDate = new Date(year, month - 1, day);
                    
                    // We don't add click handlers for adjacent month days
                    // They are always disabled
                }
                
                container.appendChild(dayEl);
            }
        }
        
        // Current month days
        for (let i = 1; i <= daysInMonth; i++) {
            const dayEl = document.createElement("div");
            dayEl.className = this.staticClass.day;
            dayEl.textContent = i;
            
            const currentDate = new Date(year, month, i);
            
            // Check if date is selectable
            if (this.isDateSelectable(currentDate)) {
                // Check if this is the selected date
                if (this.selectedDate && 
                    currentDate.getDate() === this.selectedDate.getDate() &&
                    currentDate.getMonth() === this.selectedDate.getMonth() &&
                    currentDate.getFullYear() === this.selectedDate.getFullYear()) {
                    dayEl.classList.add("selected");
                }
                
                dayEl.addEventListener("click", () => this.selectDate(currentDate));
            } else {
                dayEl.classList.add("disabled");
            }
            
            container.appendChild(dayEl);
        }
        
        // Next month days - only to complete the last week
        const lastDayOfWeek = (firstDayOfWeek + daysInMonth - 1) % 7;
        const remainingDaysInWeek = lastDayOfWeek < 6 ? 6 - lastDayOfWeek : 0;
        
        for (let i = 1; i <= remainingDaysInWeek; i++) {
            const dayEl = document.createElement("div");
            dayEl.className = `${this.staticClass.day} inactive disabled`;
            
            if (this.showAdjacentMonthDays) {
                dayEl.textContent = i;
                
                // Create date for next month day
                const nextMonthDate = new Date(year, month + 1, i);
                
                // We don't add click handlers for adjacent month days
                // They are always disabled
            }
            
            container.appendChild(dayEl);
        }
    }
    
    isDateSelectable(date) {
        if (this.minDate && date < this.minDate) return false;
        if (this.maxDate && date > this.maxDate) return false;
        return true;
    }
    
    selectDate(date) {
        this.selectedDate = date;
        this.inputField.value = this.formatDate(date);
        
        // Update the hidden field with ISO date
        if (this.hiddenField) {
            this.hiddenField.value = this.selectedDate.toISOString();
        }
        
        this.closeCalendar();
        
        // Create an enhanced data object with multiple formats
        const eventData = {
            date: this.selectedDate,
            formatted: this.formatDate(this.selectedDate),
            iso: this.selectedDate.toISOString(),
            withTimezone: this.selectedDate.toLocaleString(undefined, {
                timeZone: Intl.DateTimeFormat().resolvedOptions().timeZone,
                timeZoneName: 'short'
            })
        };
        
        // Dispatch event with enhanced data
        this.dispatchEvent('change', eventData);
    }
    
    prevMonth() {
        this.currentMonth.setMonth(this.currentMonth.getMonth() - 1);
        this.updateCalendar();
    }
    
    nextMonth() {
        this.currentMonth.setMonth(this.currentMonth.getMonth() + 1);
        this.updateCalendar();
    }
    
    updateCalendar() {
        // Remove the calendar without animation
        if (this.calendar) {
            this.calendar.remove();
            this.calendar = null;
        }
        
        // Create new calendar
        this.createCalendar();
        
        // Add fade-in class immediately without animation
        if (this.calendar) {
            this.calendar.classList.add("fade-in");
        }
    }
    
    formatDate(date) {
        let formatted = this.format;
        
        const day = date.getDate();
        const month = date.getMonth() + 1;
        const year = date.getFullYear();
        
        const months = [
            'January', 'February', 'March', 'April', 'May', 'June',
            'July', 'August', 'September', 'October', 'November', 'December'
        ];
        
        const monthsShort = [
            'Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun',
            'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'
        ];
        
        // Use regex with word boundaries to ensure exact pattern matching
        formatted = formatted.replace(/\bMMMM\b/g, months[date.getMonth()]);
        formatted = formatted.replace(/\bMMM\b/g, monthsShort[date.getMonth()]);
        formatted = formatted.replace(/\bMM\b/g, month.toString().padStart(2, '0'));
        formatted = formatted.replace(/\bM\b/g, month.toString());
        
        formatted = formatted.replace(/\bDD\b/g, day.toString().padStart(2, '0'));
        formatted = formatted.replace(/\bD\b/g, day.toString());
        
        formatted = formatted.replace(/\bYYYY\b/g, year.toString());
        formatted = formatted.replace(/\bYY\b/g, year.toString().slice(-2));
        
        return formatted;
    }
    
    formatMonthYear(date) {
        const months = [
            'January', 'February', 'March', 'April', 'May', 'June',
            'July', 'August', 'September', 'October', 'November', 'December'
        ];
        return `${months[date.getMonth()]} ${date.getFullYear()}`;
    }
    
    addEventListener(event, callback) {
        if (!this.eventListeners[event]) {
            this.eventListeners[event] = [];
        }
        this.eventListeners[event].push(callback);
    }
    
    dispatchEvent(event, data) {
        if (this.eventListeners[event]) {
            this.eventListeners[event].forEach(callback => {
                callback({ type: event, data });
            });
        }
    }
    
    getValue() {
        return this.selectedDate;
    }
    
    setValue(date) {
        this.selectedDate = new Date(date);
        this.inputField.value = this.formatDate(this.selectedDate);
        this.dispatchEvent('change', this.selectedDate);
    }
}
